// 全域切換籤王版本函式
window.toggleJiaziKingVersion = function (btn, vIndex) {
    const root = btn.closest('.jiazi-king-wrapper');
    if (!root) return; // 防呆

    // 更新按鈕樣式
    root.querySelectorAll('.king-btn').forEach(b => {
        b.style.background = 'rgba(0,0,0,0.1)';
        b.style.color = '#000';
    });
    btn.style.background = '#000';
    btn.style.color = '#fff';

    // 取得籤詩資料
    const kingData = window.poemSystems['Jiazi_60'].content[0].versions[vIndex];

    // 更新詩句
    const lines = root.querySelectorAll('.jz-poem-line');
    if (lines.length >= 4) {
        lines[0].innerText = kingData.l1;
        lines[1].innerText = kingData.l2;
        lines[2].innerText = kingData.l3;
        lines[3].innerText = kingData.l4;
    }

    // 更新籤解 (只有版本五有)
    const intentGrid = root.querySelector('.jz-intent-grid');
    if (vIndex === 4 && kingData.intents.length > 0) {
        let gridHtml = "";
        kingData.intents.forEach(item => {
            gridHtml += `<div class="jz-intent-item"><div class="jz-intent-key">${item.k}</div><div class="jz-intent-val">${item.v}</div></div>`;
        });
        intentGrid.innerHTML = gridHtml;
    } else {
        intentGrid.innerHTML = `<div style="padding: 2cqw; font-size: 4cqw; font-weight: bold; width: 100%; text-align: center;">此版本無籤解，請虔誠祈求。</div>`;
    }
};

