    // 1. 右側資訊一條龍 (去除空格，全部串在一起)
    let rightColText = `第${getCn(Number(cleanLotNum))}籤【${poem.name}】${poem.bua.replace(/\s+/g, '')}${poem.elemDir}`;

    // 2. 故事直排
    let storyHtml = "";
